function abilityText(a){let dot=a.dot||3,weaken=a.weaken||4,bonus=a.bonus||6,power=a.power||3;if(a.type==='damage')return `Deal ${a.value} damage${a.execute?`. +${a.execute} below half health.`:'.'}`;if(a.type==='hybrid')return `Deal ${a.value} damage and heal the most wounded hero for ${a.heal}.`;if(a.type==='weaken')return `Deal ${a.value} damage and reduce the next enemy attack by ${weaken}.`;if(a.type==='double')return `Deal ${a.value} damage with a 45% chance to strike twice.`;if(a.type==='poison')return `Deal ${a.value} damage and add ${dot} poison after every enemy turn.`;if(a.type==='evade')return `Deal ${a.value} damage and evade the next enemy attack.${a.cooldown?' Cooldown: 1 hero turn.':''}`;if(a.type==='pact')return `Lose 3 health to deal ${a.value} damage.`;if(a.type==='heal')return `Heal the entire party for ${a.value}.`;if(a.type==='selfheal')return `Deal ${a.value} damage and restore ${a.heal} health to yourself.`;if(a.type==='expose')return `Deal ${a.value} damage; the next hero deals +${bonus}.`;if(a.type==='meteor')return `Deal ${a.value} damage, then this ability becomes exhausted.`;if(a.type==='cry')return `Deal ${a.value} damage and empower the next two attacks by ${power}.`;return a.desc;}
function cooldownSlot(abilityName){return ABILITIES.find(a=>a.name===abilityName)?.type==='evade'?'full-evade':abilityName;}
function cooldownKey(heroId,abilityName){return `${heroId}::${cooldownSlot(abilityName)}`;}
function abilityCooldown(heroId,abilityName){return state.cooldowns?.[cooldownKey(heroId,abilityName)]||0;}
function setAbilityCooldown(heroId,abilityName,turns){if(turns>0)state.cooldowns[cooldownKey(heroId,abilityName)]=turns;}
function tickHeroCooldowns(heroId){Object.keys(state.cooldowns).forEach(key=>{if(!key.startsWith(`${heroId}::`))return;state.cooldowns[key]--;if(state.cooldowns[key]<=0)delete state.cooldowns[key];});}
function rankUpAbility(a){a.rank=Math.min(MAX_ABILITY_RANK,(a.rank||1)+1);let gain=a.type==='meteor'?3:['damage','pact'].includes(a.type)?2:1;if(typeof a.value==='number')a.value+=gain;if(a.heal)a.heal+=2;if(a.type==='poison')a.dot=(a.dot||3)+1;if(a.type==='weaken')a.weaken=(a.weaken||4)+1;if(a.type==='expose')a.bonus=(a.bonus||6)+2;if(a.type==='cry')a.power=(a.power||3)+1;a.desc=abilityText(a);return a;}
function rankPreview(a){return rankUpAbility({...a});}

