let state = {screen:'title', selected:[], world:0, level:0, livesRemaining:5, shards:0, lastShardGain:0, rewardPaid:false, encounterType:'Normal', encounterName:'', scene:null, sceneEntering:false, encounterIntro:false, cardsArriving:false, party:[], enemies:[], targetIndex:0, enemyTurnIndex:0, enemyActionCount:0, intent:null, turn:0, inspectedHeroId:null, log:[], echoes:[], echoSerial:0, equippedEchoIds:[], echoUsed:false, pendingEchoOptions:[], rewards:[], assigned:0, pendingReplacement:null, learnedAbilities:new Set(), evade:null, timeMarkedHeroId:null, boost:0, boostPower:3, lastHeroAction:null, pendingDamageBonus:0, pendingDefenseBonus:0, encounterDamageBonus:0, encounterDefenseBonus:0, shopOpen:false, shopBought:new Set(), cooldowns:{}, exhausted:new Set(), animating:false, fx:null};
const app = document.querySelector('#app');
let encounterIntroTimer=null;
let abilityHoldTimer=null;
let abilityHoldCleanupTimer=null;
let heldAbilityButton=null;

function testNav(){if(state.screen!=='game')return '';let locked=state.animating||state.encounterIntro;return `<div class="test-nav" aria-label="Playtest campaign navigation"><span>Playtest</span><label><small>World</small><select aria-label="Jump to world" onchange="jumpWorldTo(Number(this.value))" ${locked?'disabled':''}>${WORLDS.map((w,i)=>`<option value="${i}" ${i===state.world?'selected':''}>W${i+1}</option>`).join('')}</select></label><i></i><label><small>Fight</small><select aria-label="Jump to fight" onchange="jumpEncounterTo(Number(this.value))" ${locked?'disabled':''}>${[0,1,2,3,4].map(i=>`<option value="${i}" ${i===state.level?'selected':''}>F${i+1}</option>`).join('')}</select></label></div>`;}
function topbar(){return `<div class="topbar"><div class="brand">FIFTH ECHO</div><div class="run-meta">${testNav()}<div class="shards" aria-label="${state.shards} echo shards"><span>✦</span><b>${state.shards}</b> shards</div><div class="lives" aria-label="${state.livesRemaining} of 5 lives remain"><span>Lives <b>${state.livesRemaining}/5</b></span>${[0,1,2,3,4].map(i=>`<i class="life ${i>=state.livesRemaining?'lost':''}"></i>`).join('')}</div></div></div>`}
function render(){ if(state.screen==='title') title(); else if(state.screen==='select') select(); else game(); }
function title(){ app.innerHTML=`<div class="shell">${topbar()}<section class="panel hero"><div class="eyebrow">A party-building roguelite</div><h1>Fifth<br>Echo</h1><p>Five lives. Five collapsing realities. Every fallen hero can return as an Echo—and every ability you give them may decide the final battle.</p><button class="primary" onclick="state.screen='select';render()">Begin the first world</button></section></div>`; }
function equippedEchoes(){return state.equippedEchoIds.map(id=>state.echoes.find(e=>e.id===id)).filter(Boolean);}
function echoKind(a){if(a.type==='heal'||a.heal)return 'Heal';if(['poison','weaken','expose','evade','cry'].includes(a.type))return 'Debuff';return 'Damage';}
function echoArchive(){if(!state.echoes.length)return '';let equipped=equippedEchoes();return `<section class="echo-archive panel"><div class="echo-archive-copy"><div class="eyebrow">The Echo Archive · ${equipped.length}/${MAX_EQUIPPED_ECHOES} equipped</div><h3>Build your support hand</h3><p>Equip up to three fallen Echoes. During each fight, choose <b>one</b> to cast—then the entire support hand is spent until the next encounter.</p></div><div class="echo-options">${state.echoes.map(e=>{let active=state.equippedEchoIds.includes(e.id),full=!active&&equipped.length>=MAX_EQUIPPED_ECHOES;return `<article class="echo-option ${active?'active':''}"><div class="echo-option-art">${e.art?`<img src="${e.art}" alt="${e.name}'s Echo" />`:e.icon}</div><div><span>${echoKind(e.ability)} · ${e.role} Echo</span><h4>${e.name}</h4><p>${e.ability.icon} ${e.ability.name} · R${e.ability.rank||1}</p></div><div class="echo-loadout-action"><button class="${active?'selected':''}" aria-pressed="${active}" ${full?'disabled':''} onclick="toggleEchoLoadout('${e.id}')">${active?'Unequip':full?'3/3 full':'Equip'}</button></div></article>`;}).join('')}</div></section>`;}
function toggleEchoLoadout(id){if(!state.echoes.some(e=>e.id===id))return;if(state.equippedEchoIds.includes(id))state.equippedEchoIds=state.equippedEchoIds.filter(echoId=>echoId!==id);else if(state.equippedEchoIds.length<MAX_EQUIPPED_ECHOES)state.equippedEchoIds.push(id);render();}
function select(){ app.innerHTML=`<div class="shell">${topbar()}<div class="section-head"><div><div class="eyebrow">Form your expedition</div><h2>Choose three heroes</h2><p>Each begins with one signature ability. Their next abilities are yours to shape.</p></div><div><b>${state.livesRemaining}</b> lives remain · ${state.selected.length} / 3 chosen</div></div>${echoArchive()}<div class="roster">${HEROES.map(h=>`<button class="hero-card ${h.art?'with-art':''} ${state.selected.includes(h.id)?'selected':''}" onclick="toggleHero('${h.id}')"><div class="portrait-stage">${h.art?`<img class="hero-art" src="${h.art}" alt="${h.name}, ${h.role}" />`:`<div class="portrait">${h.icon}</div>`}<span class="vitality">♥ ${h.hp}</span></div><div class="card-copy"><div class="class">${h.role}</div><h3>${h.name}</h3><div class="signature"><span>${h.start.name}</span><b>${h.start.icon}</b></div><p>${h.start.desc}</p><div class="passive" title="${h.passiveDesc}">${h.passive}<small>${h.passiveDesc}</small></div></div></button>`).join('')}</div><div class="action-row"><button class="primary" ${state.selected.length!==3?'disabled':''} onclick="begin()">${state.livesRemaining<5?`Return to ${WORLDS[state.world].name}`:'Enter the world'}</button></div></div>`; }
function toggleHero(id){ state.selected=state.selected.includes(id)?state.selected.filter(x=>x!==id):(state.selected.length<3?[...state.selected,id]:state.selected); render(); }
function begin(){ state.party=state.selected.map(id=>{let h=HEROES.find(x=>x.id===id);return {...h,maxHp:h.hp,currentHp:h.hp,burn:0,passiveReady:true,abilities:[{...h.start,rank:1}]}});state.party.forEach(h=>h.abilities.forEach(a=>state.learnedAbilities.add(a.name)));state.screen='game';startEncounter(); }
function preloadEncounterAssets(...sources){if(typeof Image==='undefined')return;sources.filter(Boolean).forEach(src=>{let image=new Image();image.decoding='async';image.src=src;});}
function startEncounter(){
 let m=WORLDS[state.world].mobs[state.level],count=m[5]||1,mechanics=m[8]||{};
 if(encounterIntroTimer)clearTimeout(encounterIntroTimer);
 state.encounterName=m[0];state.encounterType=m[6]||'Normal';state.scene=m[7]||null;
 state.encounterDamageBonus=state.pendingDamageBonus;state.pendingDamageBonus=0;state.encounterDefenseBonus=state.pendingDefenseBonus;state.pendingDefenseBonus=0;
 state.rewardPaid=false;state.lastShardGain=0;state.shopOpen=false;
 state.party.forEach(h=>{h.burn=0;h.chill=0;h.passiveReady=true;});
 state.enemies=Array.from({length:count},(_,i)=>({name:m[0],internalName:count>1?`${m[0]} ${String.fromCharCode(65+i)}`:m[0],slot:i,icon:m[1],art:m[4],maxHp:m[2],hp:m[2],damage:m[3],burn:mechanics.burn||0,burnBurst:mechanics.burnBurst||4,pattern:mechanics.pattern||'basic',armor:0,veil:0,clock:0,weakened:0,expose:0,poison:0}));
 state.targetIndex=0;state.enemyTurnIndex=0;state.enemyActionCount=0;state.intent=null;state.turn=Math.max(0,state.party.findIndex(h=>h.currentHp>0));state.inspectedHeroId=state.party.find(h=>h.currentHp>0)?.id||null;
 state.log=[count>2?`<b>${count} enemies</b> surround the party.`:count>1?`<b>${count} enemies</b> close in from opposite sides.`:`<b>${m[0].startsWith('The ')?m[0]:`The ${m[0]}`}</b> blocks your path.`];
 let mechanic=mechanicSummary(mechanics.pattern);if(mechanic)state.log.push(mechanic);if(mechanics.burn)state.log.push('<b>Burn:</b> enemy hits add flame. At 3 stacks, it bursts and clears.');if(state.encounterDamageBonus)state.log.push(`<b>Sharpened Sigil:</b> hero attacks deal +${state.encounterDamageBonus} damage.`);if(state.encounterDefenseBonus)state.log.push(`<b>Warding Charm:</b> incoming damage is reduced by ${state.encounterDefenseBonus}.`);
 state.evade=null;state.timeMarkedHeroId=null;state.boost=0;state.boostPower=3;state.lastHeroAction=null;state.cooldowns={};state.exhausted=new Set();state.echoUsed=false;state.animating=true;state.fx=null;state.sceneEntering=true;state.encounterIntro=true;state.cardsArriving=false;
 preloadEncounterAssets(m[4],state.scene?.cutout,state.scene?.bg);
 planEnemyIntent();
 let reducedMotion=typeof matchMedia==='function'&&matchMedia('(prefers-reduced-motion: reduce)').matches;encounterIntroTimer=setTimeout(()=>finishEncounterIntro(false),reducedMotion?60:encounterIntroDuration());render();
}
function pluralEnemy(name){if(name.endsWith('Wretch'))return name.replace(/Wretch$/,'Wretches');if(name.endsWith('s'))return name;return `${name}s`;}
function encounterIntroDuration(){return state.encounterType==='Boss'?5000:state.encounterType==='Elite'?4200:3600;}
function encounterChoreography(){let count=state.enemies.length;if(count===3)return [{x:18,bottom:4,entry:'-22vw',delay:.04,mirror:1},{x:50,bottom:8,entry:'0vw',delay:.28,mirror:-1},{x:82,bottom:4,entry:'22vw',delay:.12,mirror:-1}];if(count===2)return [{x:34,bottom:0,entry:'-10vw',delay:.06,mirror:1},{x:66,bottom:2,entry:'10vw',delay:.24,mirror:-1}];if(state.encounterType==='Boss')return [{x:50,bottom:-14,entry:'0vw',delay:.28,mirror:1}];if(state.encounterType==='Elite')return [{x:50,bottom:-12,entry:'0vw',delay:.12,mirror:1}];return [{x:50,bottom:0,entry:'0vw',delay:.12,mirror:1}];}
function encounterReveal(){let count=state.enemies.length,choreography=encounterChoreography(),title=count===1?`${state.encounterName} emerges`:`${pluralEnemy(state.encounterName)} emerge`,kind=state.encounterType.toLowerCase(),threat=kind==='boss'?'A sovereign stirs':kind==='elite'?'An elite guardian rises':'Ambush',cutout=state.scene?.cutout,timeStop=state.world===3&&kind==='boss'?'<div class="time-stop-ring"><i></i><i></i><i></i></div>':'',fifthBreak=state.world===4&&kind==='boss'?'<div class="fifth-break"><i></i><i></i><i></i><i></i><i></i></div>':'';return `<section class="encounter-reveal world-${state.world+1} scene-${state.level+1} ${kind} count-${count}" aria-label="${title}"><div class="reveal-vignette"></div><div class="reveal-fog fog-one"></div><div class="reveal-fog fog-two"></div>${kind==='boss'?'<div class="boss-omen"><i></i><i></i><i></i></div>':''}${timeStop}${fifthBreak}${state.enemies.map((e,i)=>{let c=choreography[i]||{x:50,bottom:0,entry:'0vw',delay:i*.16,mirror:1},style=`--reveal-x:${c.x}%;--reveal-bottom:${c.bottom}vh;--entry-x:${c.entry};--reveal-delay:${c.delay}s;--reveal-mirror:${c.mirror}`,cinematicArt=cutout||e.art;return cinematicArt?`<div class="reveal-creature ${cutout?'is-cutout':''}" style="${style}"><span class="creature-shadow"></span><img src="${cinematicArt}" alt="" /></div>`:`<div class="reveal-symbol" style="${style}">${e.icon}</div>`}).join('')}<div class="reveal-copy"><div class="reveal-threat">${threat} · Fight ${state.level+1} of 5</div><div class="scene-kicker">${state.scene?.name||WORLDS[state.world].name}</div><h2>${title}</h2><p>${state.scene?.intro||'Something moves beyond the edge of sight.'}</p></div><div class="card-forming" aria-hidden="true">The encounter takes shape</div><button class="skip-intro" onclick="skipEncounterIntro()">Skip encounter</button></section>`;}
function commitEncounterCards(){state.encounterIntro=false;state.sceneEntering=false;state.cardsArriving=true;state.animating=false;render();setTimeout(()=>state.cardsArriving=false,1050);}
function finishEncounterIntro(){if(!state.encounterIntro)return;if(encounterIntroTimer){clearTimeout(encounterIntroTimer);encounterIntroTimer=null;}commitEncounterCards();}
function skipEncounterIntro(){finishEncounterIntro(true);}
function ashenAmbience(){let ash=Array.from({length:26},(_,i)=>`<i class="ash-flake" style="--ash-x:${(i*37)%100}%;--ash-size:${1+(i%4)}px;--ash-delay:${-(i*.61)}s;--ash-time:${8+(i%6)*1.3}s;--ash-drift:${-22+(i%7)*8}px"></i>`).join(''),embers=Array.from({length:14},(_,i)=>`<i class="world-ember" style="--ember-x:${6+(i*31)%88}%;--ember-delay:${-(i*.77)}s;--ember-time:${5+(i%5)*1.2}s;--ember-sway:${-28+(i%6)*11}px"></i>`).join(''),special=state.level===0?'<span class="village-fire-glow"></span><span class="ash-smoke smoke-a"></span>':state.level===1?'<span class="village-fire-glow square-glow"></span><span class="ash-smoke smoke-b"></span>':state.level===2?'<span class="basilica-pull"></span>':state.level===3?'<span class="courtyard-heat"></span><span class="swing-chain chain-left"></span><span class="swing-chain chain-right"></span>':'<span class="last-flame-pulse"></span>';return `<div class="scene-ambience ashen-life ashen-${state.level}" aria-hidden="true">${special}${ash}${embers}</div>`;}
