function enemyStatusMarkup(e){if(e.hp<=0)return '';let effects=[];if(e.armor)effects.push(`<span class="enemy-status armor" title="Armor absorbs incoming damage">🛡 ${e.armor}</span>`);if(e.veil)effects.push(`<span class="enemy-status veil" title="Veil reduces the next hero hit by ${e.veil}">◌ ${e.veil}</span>`);if(e.pattern==='midnight')effects.push(`<span class="enemy-status time" title="The third stolen hour empowers Midnight Decree">◷ ${e.clock||0}/3</span>`);if(e.pattern==='endfive')effects.push(`<span class="enemy-status time fifth-status" title="The next invocation advances the Fivefold End">✦ ${e.clock||0}/5</span>`);if(e.poison)effects.push(`<span class="enemy-status poison" title="Takes ${e.poison} poison damage after every enemy turn">☠ ${e.poison}</span>`);if(e.weakened)effects.push(`<span class="enemy-status weakened" title="Next attack deals ${e.weakened} less damage">↓ ${e.weakened}</span>`);if(e.expose)effects.push(`<span class="enemy-status exposed" title="Next hero attack gains ${e.expose} damage">◎ +${e.expose}</span>`);return effects.length?`<div class="enemy-statuses" aria-label="Active effects">${effects.join('')}</div>`:'';}
function memberCard(h,active,inspected){let pct=Math.max(0,h.currentHp/h.maxHp*100),shownHp=Math.max(0,h.currentHp),burn=h.burn||0,chill=h.chill||0,timeMarked=state.timeMarkedHeroId===h.id,evading=state.evade===h.id,dead=h.currentHp<=0,locked=dead||state.animating,healFx=(state.fx?.heals||[]).filter(x=>x.heroId===h.id).reduce((sum,x)=>sum+x.amount,0),multiDamage=(state.fx?.heroDamages||[]).filter(x=>x.heroId===h.id).reduce((sum,x)=>sum+x.amount,0),singleDamage=state.fx?.heroDamage?.heroId===h.id?state.fx.heroDamage.amount:0,damageFx=multiDamage+singleDamage,evaded=state.fx?.evadedHeroId===h.id,passiveSpent=h.passiveOnce&&h.passiveReady===false;return `<article class="battle-hero-card ${active?.id===h.id?'active-turn':''} ${inspected?.id===h.id?'inspected':''} ${dead?'fallen':''} ${locked?'hero-locked':''} ${state.fx?.heroId===h.id?'hero-strike':''} ${damageFx?'hero-hit':''} ${healFx?'hero-healed':''}" ${locked?'':`onclick="inspectHero('${h.id}')"`} aria-label="${h.name}, ${shownHp} of ${h.maxHp} health${burn?`, ${burn} of 3 Burn`:''}${chill?`, Chilled by ${chill}`:''}${timeMarked?', clock-marked':''}${evading?', Evade ready':''}. ${h.passive}${passiveSpent?' spent':' active'}">${damageFx?`<span class="combat-number damage-number">-${damageFx}</span>`:''}${healFx?`<span class="combat-number heal-number">+${healFx}</span>`:''}${evaded?`<span class="combat-number evade-number">Evade</span>`:''}<div class="battle-hero-art">${h.art?`<img src="${h.art}" alt="${h.name}" />`:h.icon}</div><div class="battle-hero-copy"><div class="class">${active?.id===h.id?'Current turn':h.role}</div><h3>${h.name}</h3><div class="hp-row"><div class="bar"><span style="width:${pct}%"></span></div><b>${shownHp}</b><small>/${h.maxHp}</small></div><span class="passive-status ${passiveSpent?'spent':''}" title="${h.passiveDesc}">${h.passive}${passiveSpent?' · spent':''}</span>${burn?`<span class="burn-status" title="At 3 stacks, Burn bursts and clears">🔥 ${burn}/3</span>`:''}${chill?`<span class="chill-status" title="The next damaging action deals ${chill} less damage">❄ −${chill} next hit</span>`:''}${timeMarked?`<span class="time-mark-status" title="The next Tock hunts this hero">◷ Clock-marked</span>`:''}${evading?`<span class="evade-status" title="The next enemy attack against this hero is evaded">🌘 Evade ready</span>`:''}</div><div class="hero-abilities" aria-label="${h.name}'s abilities">${heroAbilitySlots(h,active,dead)}</div></article>`;}
function enemyCard(e,i){let pct=Math.max(0,e.hp/e.maxHp*100),dead=e.hp<=0,damageFx=(state.fx?.enemyDamage||[]).filter(x=>x.index===i).reduce((sum,x)=>sum+x.amount,0),healFx=state.fx?.enemyHeal?.index===i?state.fx.enemyHeal.amount:0,hit=state.fx?.hitTargets?.includes(i),defeated=state.fx?.defeated?.includes(i),acting=state.intent?.attackerIndex===i&&!dead;return `<button class="enemy-card enemy-select ${state.targetIndex===i&&!dead?'targeted':''} ${acting?'intending':''} ${dead?'defeated':''} ${hit?'enemy-hit':''} ${state.fx?.enemyAttackerIndex===i?'enemy-strike':''} ${defeated?'just-defeated':''}" style="--enemy-index:${i}" onclick="selectTarget(${i})" ${dead||state.animating?'disabled':''}>${damageFx?`<span class="combat-number damage-number">-${damageFx}</span>`:''}${healFx?`<span class="combat-number heal-number">+${healFx}</span>`:''}${e.art?`<div class="enemy-portrait"><img class="${i%2?'mirrored':''}" src="${e.art}" alt="${e.name}" /></div>`:`<div class="enemy-art">${e.icon}</div>`}<div class="enemy-data"><div class="class">${dead?'Defeated':state.targetIndex===i?'Current target':state.encounterType}</div><h2>${e.name}</h2>${enemyStatusMarkup(e)}<div class="hp-row"><div class="bar enemy"><span style="width:${pct}%"></span></div><b>${Math.max(0,e.hp)}</b><small>/${e.maxHp}</small></div>${enemyIntentMarkup(e,i,dead)}</div></button>`;}
function selectTarget(i){if(state.enemies[i]?.hp>0){state.targetIndex=i;render();}}
function currentTarget(){let target=state.enemies[state.targetIndex];if(!target||target.hp<=0){state.targetIndex=state.enemies.findIndex(e=>e.hp>0);target=state.enemies[state.targetIndex];}return target;}
function nextLiving(){return state.party.find(h=>h.currentHp>0);}
function lowest(){return [...state.party].filter(h=>h.currentHp>0).sort((a,b)=>a.currentHp/a.maxHp-b.currentHp/b.maxHp)[0];}
function heal(h,n){if(!h)return;let before=h.currentHp;h.currentHp=Math.min(h.maxHp,h.currentHp+n);let restored=Math.max(0,h.currentHp-before);if(restored&&state.fx?.kind==='hero')state.fx.heals.push({heroId:h.id,amount:restored});}
function recordHeroDamage(heroId,amount){if(!state.fx||amount<=0)return;state.fx.heroDamages=state.fx.heroDamages||[];let existing=state.fx.heroDamages.find(x=>x.heroId===heroId);if(existing)existing.amount+=amount;else state.fx.heroDamages.push({heroId,amount});}
function applyHeroDamage(hero,amount,source='enemy'){if(!hero||hero.currentHp<=0||amount<=0)return 0;let ward=source!=='pact'?(state.encounterDefenseBonus||0):0,damage=Math.max(0,amount-ward),steadfast=damage>0&&source!=='pact'&&hero.passive==='Steadfast'&&hero.passiveReady;if(ward)state.log.push(`<b>Warding Charm</b> reduces damage to ${hero.name} by ${Math.min(ward,amount)}.`);if(steadfast){damage=Math.max(0,damage-3);hero.passiveReady=false;state.log.push(`<b>${hero.name}'s Steadfast</b> reduces the hit by 3.`);}let before=hero.currentHp,sol=state.party.find(h=>h.passive==='Last Light'&&h.currentHp>0&&h.passiveReady);hero.currentHp=Math.max(0,hero.currentHp-damage);if(hero.currentHp<=0&&sol){hero.currentHp=1;sol.passiveReady=false;state.log.push(`<b>${sol.name}'s Last Light</b> keeps ${hero.name} standing at 1 health.`);}let dealt=Math.max(0,before-hero.currentHp);recordHeroDamage(hero.id,dealt);return dealt;}
function applyBurn(hero,stacks,burst=4){if(!hero||hero.currentHp<=0||!stacks)return 0;hero.burn=(hero.burn||0)+stacks;state.log.push(`<b>${hero.name}</b> gains ${stacks} Burn (${hero.burn}/3).`);if(hero.burn<3)return 0;hero.burn=0;let dealt=applyHeroDamage(hero,burst,'burn');state.log.push(`Burn erupts for <b>${burst}</b> damage and clears.`);return dealt;}
function hit(n,user){let target=currentTarget();if(!target)return 0;let index=state.enemies.indexOf(target),before=target.hp,expose=target.expose||0,boost=state.boost>0?state.boostPower:0,sigil=state.encounterDamageBonus||0,opportunist=user.passive==='Opportunist'&&target.hp<target.maxHp/2?2:0,keenEye=user.passive==='Keen Eye'&&user.passiveReady?4:0,total=n+expose+boost+sigil+opportunist+keenEye,chilled=Math.min(user.chill||0,total);if(chilled){user.chill=0;total-=chilled;state.log.push(`<b>Chill</b> reduces ${user.name}'s attack by ${chilled}.`);}let veiled=Math.min(target.veil||0,total);if(keenEye){user.passiveReady=false;state.log.push(`<b>${user.name}'s Keen Eye</b> adds 4 damage.`);}if(opportunist)state.log.push(`<b>${user.name}'s Opportunist</b> adds 2 damage.`);if(sigil)state.log.push(`<b>Sharpened Sigil</b> adds ${sigil} damage.`);if(expose){state.log.push(`The exposed weakness adds <b>${expose}</b> damage.`);target.expose=0;}if(boost>0)state.boost--;if(veiled){target.veil=0;total-=veiled;state.log.push(`${target.name}'s Veil dissolves and reduces the hit by <b>${veiled}</b>.`);}let blocked=Math.min(target.armor||0,total);if(blocked){target.armor-=blocked;total-=blocked;state.log.push(`${target.name}'s armor blocks <b>${blocked}</b> damage.`);}target.hp-=total;if(state.fx){if(total)state.fx.enemyDamage.push({index,amount:total});if(!state.fx.hitTargets.includes(index))state.fx.hitTargets.push(index);if(before>0&&target.hp<=0&&!state.fx.defeated.includes(index))state.fx.defeated.push(index);}state.log.push(`<b>${user.name}</b> deals ${total} damage to ${target.name}.`);return total;}
function useAbility(id,index){let user=state.party.find(h=>h.id===id),active=state.party[state.turn%state.party.length],a=user?.abilities[index],target=currentTarget();if(state.animating||!user||!a||user.currentHp<=0||active?.id!==user.id||!target||abilityCooldown(id,a.name))return;tickHeroCooldowns(id);if(a.cooldown)setAbilityCooldown(id,a.name,a.cooldown);state.animating=true;state.fx={kind:'hero',heroId:id,abilityName:a.name,enemyDamage:[],hitTargets:[],defeated:[],heals:[],heroDamages:[],heroDamage:null};state.lastHeroAction={heroId:id,name:a.name,damage:Math.max(0,a.value||0)};
 if(a.type==='damage') hit(a.value+(a.execute&&target.hp<target.maxHp/2?a.execute:0),user);
 if(a.type==='hybrid'){hit(a.value,user);heal(lowest(),a.heal);state.log.push(`Restorative light heals an ally for <b>${a.heal}</b>.`)}
 if(a.type==='weaken'){hit(a.value,user);if(target.hp>0){let weaken=(a.weaken||4)+(user.passive==='Lingering Curse'?2:0);target.weakened=Math.max(target.weakened,weaken);if(user.passive==='Lingering Curse')state.log.push(`<b>${user.name}'s Lingering Curse</b> deepens Weaken by 2.`);}}
 if(a.type==='double'){hit(a.value,user);if(Math.random()<.45){hit(a.value,user);state.log.push('The second shot finds its mark!')}}
 if(a.type==='poison'){hit(a.value,user);if(target.hp>0){let poison=(a.dot||3)+(user.passive==='Lingering Curse'?1:0);target.poison+=poison;if(user.passive==='Lingering Curse')state.log.push(`<b>${user.name}'s Lingering Curse</b> adds 1 Poison.`);}}
 if(a.type==='evade'){hit(a.value,user);state.evade=user.id;if(a.cooldown)state.log.push(`<b>${a.name}</b> enters cooldown for one ${user.name} turn.`);}
 if(a.type==='pact'){applyHeroDamage(user,3,'pact');hit(a.value,user);}
 if(a.type==='heal'){state.party.forEach(h=>heal(h,a.value));state.log.push(`<b>${user.name}</b> mends the party for ${a.value}.`)}
 if(a.type==='selfheal'){hit(a.value,user);heal(user,a.heal);}
 if(a.type==='expose'){hit(a.value,user);if(target.hp>0)target.expose=a.bonus||6;}
 if(a.type==='meteor'){hit(a.value,user);state.exhausted.add(a.name);}
 if(a.type==='cry'){hit(a.value,user);state.boost=2;state.boostPower=a.power||3;}
 if(state.party.every(h=>h.currentHp<=0)){render();setTimeout(partyFell,700);return;}if(state.enemies.every(e=>e.hp<=0)){render();setTimeout(victory,700);return;}currentTarget();if(!state.enemies[state.intent?.attackerIndex]||state.enemies[state.intent.attackerIndex].hp<=0||(state.intent?.targetId&&!state.party.some(h=>h.id===state.intent.targetId&&h.currentHp>0)))planEnemyIntent();render();setTimeout(enemyTurn,500);}
function enemyTurn(){state.fx={kind:'enemy',enemyDamage:[],hitTargets:[],defeated:[],heals:[],heroDamages:[],heroDamage:null,enemyAttackerIndex:null,enemyHeal:null,evadedHeroId:null};state.enemies.filter(e=>e.hp>0&&e.poison).forEach(e=>{let index=state.enemies.indexOf(e),before=e.hp;e.hp-=e.poison;state.fx.enemyDamage.push({index,amount:e.poison});state.fx.hitTargets.push(index);if(before>0&&e.hp<=0)state.fx.defeated.push(index);state.log.push(`Poison deals <b>${e.poison}</b> damage to ${e.name}.`);});if(state.enemies.every(e=>e.hp<=0)){render();setTimeout(victory,700);return;}let intended=state.enemies[state.intent?.attackerIndex],target=state.party.find(h=>h.id===state.intent?.targetId);if(!intended||intended.hp<=0||(state.intent?.targetId&&(!target||target.currentHp<=0)))planEnemyIntent();let intent=state.intent,attacker=state.enemies[intent?.attackerIndex];if(!intent||!attacker){if(state.party.every(h=>h.currentHp<=0)){render();setTimeout(partyFell,700);}else{state.animating=false;state.fx=null;render();}return;}state.fx.enemyAttackerIndex=intent.attackerIndex;let damage=Math.max(intent.damage?1:0,intent.damage-(attacker.weakened||0)),damaging=!['regrow','guard','royalguard','rite'].includes(intent.kind);
 if(intent.kind==='regrow'){let wounded=state.enemies.filter(e=>e.hp>0&&e.hp<e.maxHp).sort((a,b)=>(b.maxHp-b.hp)-(a.maxHp-a.hp))[0];if(wounded){let before=wounded.hp;wounded.hp=Math.min(wounded.maxHp,wounded.hp+intent.healAmount);let restored=wounded.hp-before;state.fx.enemyHeal={index:state.enemies.indexOf(wounded),amount:restored};state.log.push(`<b>${attacker.name}</b> uses Regrow and restores ${restored} health.`);}else state.log.push(`<b>${attacker.name}</b> finds no wound for Regrow.`);}
 else if(intent.kind==='guard'){attacker.armor=Math.min(12,(attacker.armor||0)+intent.armorAmount);state.log.push(`<b>${attacker.name}</b> raises Ash Guard and gains ${intent.armorAmount} armor.`);}
 else if(intent.kind==='royalguard'){state.enemies.filter(e=>e.hp>0).forEach(e=>e.armor=Math.min(12,(e.armor||0)+intent.armorAmount));state.log.push(`<b>${attacker.name}</b> commands Hold the Gate. Every living Knight gains ${intent.armorAmount} armor.`);}
 else if(intent.kind==='rite'){state.log.push(`<b>${attacker.name}</b> performs Censer Rite.`);state.party.filter(h=>h.currentHp>0).forEach(h=>applyBurn(h,intent.burn,attacker.burnBurst));}
 else if(intent.all){state.log.push(`<b>${attacker.name}</b> unleashes ${intent.name} on the entire party.`);state.party.filter(h=>h.currentHp>0).forEach(h=>{if(state.evade===h.id){state.log.push(`<b>${h.name}</b> slips through ${intent.name}.`);state.fx.evadedHeroId=h.id;state.evade=null;return;}applyHeroDamage(h,damage,intent.name);if(h.currentHp>0&&intent.burn)applyBurn(h,intent.burn,attacker.burnBurst);if(h.currentHp>0&&intent.chill)h.chill=Math.max(h.chill||0,intent.chill);});if(['masquerade','endfive'].includes(intent.kind)&&intent.healAmount){let before=attacker.hp;attacker.hp=Math.min(attacker.maxHp,attacker.hp+intent.healAmount);let restored=attacker.hp-before;if(restored){state.fx.enemyHeal={index:intent.attackerIndex,amount:restored};state.log.push(`${attacker.name} gathers the collapsing reality and restores <b>${restored}</b> health.`);}}}
 else {let victim=state.party.find(h=>h.id===intent.targetId);if(state.evade===victim?.id){state.log.push(`<b>${victim.name}</b> slips through ${attacker.name}'s ${intent.name}.`);state.fx.evadedHeroId=victim.id;state.evade=null;}else if(victim){let dealt=applyHeroDamage(victim,damage,intent.name);state.log.push(`${attacker.name} uses <b>${intent.name}</b> on ${victim.name} for ${dealt}.`);if(victim.currentHp>0&&intent.burn)applyBurn(victim,intent.burn,attacker.burnBurst);if(['drain','feast','devour','endfive'].includes(intent.kind)&&dealt){let before=attacker.hp;attacker.hp=Math.min(attacker.maxHp,attacker.hp+intent.healAmount);let restored=attacker.hp-before;if(restored){state.fx.enemyHeal={index:intent.attackerIndex,amount:restored};state.log.push(`${attacker.name} feeds and restores <b>${restored}</b> health.`);}}}}
 let resolvedVictim=state.party.find(h=>h.id===intent.targetId),wasEvaded=state.fx.evadedHeroId===resolvedVictim?.id;
 if(intent.kind==='tick'&&resolvedVictim?.currentHp>0&&!wasEvaded){state.timeMarkedHeroId=resolvedVictim.id;state.log.push(`<b>${resolvedVictim.name}</b> is clock-marked. The next Tock will hunt them.`);}
 if(intent.kind==='tock')state.timeMarkedHeroId=null;
 if(['foretell','devour'].includes(intent.kind)&&resolvedVictim?.currentHp>0&&!wasEvaded){resolvedVictim.chill=Math.max(resolvedVictim.chill||0,intent.chill);state.log.push(`<b>${resolvedVictim.name}</b> is Chilled. Their next attack deals ${intent.chill} less damage.`);}
 if(intent.kind==='fracture'){state.enemies.filter(e=>e.hp>0).forEach(e=>e.veil=Math.max(e.veil||0,3));state.log.push('The fracture folds around every living Wraith as <b>3 Veil</b>.');}
 if(intent.kind==='toll'&&intent.sealHeroId&&intent.sealAbilityName){let key=cooldownKey(intent.sealHeroId,intent.sealAbilityName);state.cooldowns[key]=Math.max(state.cooldowns[key]||0,1);let sealedHero=state.party.find(h=>h.id===intent.sealHeroId);state.log.push(`<b>Suspended Toll</b> seals ${sealedHero?.name||'the caster'}'s ${intent.sealAbilityName} for one turn.`);}
 if(intent.kind==='midnight'){attacker.clock=intent.clockAfter;state.log.push(intent.clockAfter?`The stolen clock advances to <b>${intent.clockAfter}/3</b>.`:'<b>Midnight strikes.</b> The stolen clock begins again.');}
 if(intent.kind==='whisperstep'&&attacker.hp>0){attacker.veil=5;state.log.push(`<b>${attacker.name}</b> fades behind a Veil that will reduce the next hero hit by 5.`);}
 if(intent.kind==='discord'&&intent.chill)state.log.push(`The Worldless Hymn Frays every surviving hero's next attack by <b>${intent.chill}</b>.`);
 if(intent.kind==='erase'&&attacker.hp>0){attacker.veil=5;state.log.push(`<b>${attacker.name}</b> folds into a 5-point Veil.`);}
 if(intent.kind==='usurp'&&attacker.hp>0){attacker.armor=Math.min(12,(attacker.armor||0)+intent.armorAmount);state.log.push(`<b>${attacker.name}</b> seals the stolen mastery into ${intent.armorAmount} armor.`);}
 if(intent.kind==='endfive'){attacker.clock=intent.clockAfter;state.log.push(intent.clockAfter?`The Fivefold End advances to <b>${intent.clockAfter}/5</b>.`:'<b>The fifth echo collapses.</b> The cycle begins again.');}
 if(damaging)attacker.weakened=0;state.enemyActionCount++;state.enemyTurnIndex++;if(state.party.every(h=>h.currentHp<=0)){render();setTimeout(partyFell,700);return;}do{state.turn++}while(state.party[state.turn%state.party.length].currentHp<=0);state.inspectedHeroId=state.party[state.turn%state.party.length].id;planEnemyIntent();render();setTimeout(()=>{state.animating=false;state.fx=null;render();},620);}
function rollRewards(){let rewards=[],used=new Set();for(let slot=0;slot<2;slot++){let fresh=REWARD_ABILITIES.filter(a=>!state.learnedAbilities.has(a.name)&&!used.has(a.name));let upgrades=state.party.flatMap(h=>h.abilities.map((a,index)=>({hero:h,ability:a,index}))).filter(x=>(x.ability.rank||1)<MAX_ABILITY_RANK&&!used.has(x.ability.name));let allowDuplicate=!rewards.some(r=>r.upgrade),takeDuplicate=upgrades.length&&(!fresh.length||(allowDuplicate&&Math.random()<DUPLICATE_CHANCE));if(takeDuplicate){let pick=upgrades[Math.floor(Math.random()*upgrades.length)],preview=rankPreview(pick.ability);rewards.push({...preview,upgrade:true,sourceName:pick.ability.name,targetHeroId:pick.hero.id,targetAbilityIndex:pick.index});used.add(pick.ability.name);}else if(fresh.length){let pick=fresh[Math.floor(Math.random()*fresh.length)];rewards.push({...pick,rank:1,desc:abilityText({...pick,rank:1})});used.add(pick.name);}else if(upgrades.length){let pick=upgrades[Math.floor(Math.random()*upgrades.length)],preview=rankPreview(pick.ability);rewards.push({...preview,upgrade:true,sourceName:pick.ability.name,targetHeroId:pick.hero.id,targetAbilityIndex:pick.index});used.add(pick.ability.name);}}return rewards;}
function victoryShardReward(){return state.encounterType==='Boss'?25:state.encounterType==='Elite'?20:10;}
function victory(){if(state.screen!=='game'||state.enemies.some(e=>e.hp>0))return;state.animating=false;state.fx=null;if(!state.rewardPaid){state.lastShardGain=victoryShardReward();state.shards+=state.lastShardGain;state.rewardPaid=true;}if(state.level===4&&state.world===4){endGame();return;}state.rewards=rollRewards();state.assigned=0;state.pendingReplacement=null;render();showRewards();}
function rewardActions(a,i){if(a.given)return `<div class="assigned">✓ ${a.given}</div>`;if(a.upgrade){let h=state.party.find(x=>x.id===a.targetHeroId);return `<div class="rank-action"><button onclick="claimUpgrade(${i})">${h.icon} Rank up ${h.name}'s ${a.name}</button><small>No ability slot required</small></div>`;}let pending=state.pendingReplacement;if(pending?.rewardIndex===i){let h=state.party.find(x=>x.id===pending.heroId);return `<div class="replacement"><div class="replacement-title">${h.name} is full · replace one ability</div>${h.abilities.map((old,slot)=>{let locked=state.rewards.some(r=>r.upgrade&&!r.given&&r.targetHeroId===h.id&&r.sourceName===old.name);return `<button ${locked?'disabled':''} onclick="replaceAbility(${i},'${h.id}',${slot})"><span>${old.icon}</span><b>${old.name} · R${old.rank||1}</b><small>${locked?'Claim its pending rank first':`Replace with ${a.name}`}</small></button>`;}).join('')}<button class="cancel-swap" onclick="cancelReplacement()">Cancel replacement</button></div>`;}return `<div class="assign">${state.party.map(h=>`<button onclick="assignReward(${i},'${h.id}')">${h.icon} ${h.name}${h.currentHp<=0?' · Fallen':h.abilities.length>=4?' · Swap':' · '+h.abilities.length+'/4'}</button>`).join('')}</div>`;}
function showRewards(){let done=state.assigned===state.rewards.length,label=done?'Continue onward':state.assigned?'Continue without the other reward':'Continue without rewards';document.body.insertAdjacentHTML('beforeend',`<div class="overlay" id="modal"><section class="panel modal"><div class="eyebrow">Victory reward · +${state.lastShardGain} shards</div><h2>Two abilities survived</h2>${state.scene?.outro?`<div class="story-beat"><span>${state.scene.name}</span><p>${state.scene.outro}</p></div>`:''}<p>New abilities are most common. Uncommon duplicates rank up the equipped copy without using another slot. Every reward is optional.</p><div class="rewards">${state.rewards.map((a,i)=>`<div class="reward-card ${a.upgrade?'rank-reward':''} ${state.pendingReplacement?.rewardIndex===i?'swapping':''}"><div class="icon">${a.icon}</div><div class="reward-rank">${a.upgrade?`Rank up · R${a.rank}`:'New ability · R1'}</div><h3>${a.name}</h3><p>${abilityText(a)}</p>${rewardActions(a,i)}</div>`).join('')}</div><div class="reward-footer"><button class="primary" onclick="continueRun()">${label}</button>${done?'':`<small>Unclaimed rewards will be left behind.</small>`}</div></section></div>`)}
function claimUpgrade(i){let reward=state.rewards[i],h=state.party.find(x=>x.id===reward?.targetHeroId),a=h?.abilities.find(x=>x.name===reward?.sourceName);if(!reward||!reward.upgrade||reward.given||!a)return;rankUpAbility(a);reward.given=`${h.name}'s ${a.name} reached Rank ${a.rank}`;state.assigned++;document.querySelector('#modal').remove();showRewards();}
function assignReward(i,id){let a=state.rewards[i],h=state.party.find(x=>x.id===id);if(!a||a.upgrade||a.given||!h)return;if(h.abilities.length>=4){state.pendingReplacement={rewardIndex:i,heroId:id};document.querySelector('#modal').remove();showRewards();return;}h.abilities.push({...a,rank:1,desc:abilityText(a)});state.learnedAbilities.add(a.name);a.given=`Given to ${h.name}`;state.assigned++;state.pendingReplacement=null;document.querySelector('#modal').remove();showRewards();}
function replaceAbility(i,id,slot){let a=state.rewards[i],h=state.party.find(x=>x.id===id),old=h?.abilities[slot],locked=state.rewards.some(r=>r.upgrade&&!r.given&&r.targetHeroId===id&&r.sourceName===old?.name);if(!a||a.upgrade||a.given||!h||!old||locked)return;h.abilities.splice(slot,1,{...a,rank:1,desc:abilityText(a)});state.learnedAbilities.add(a.name);a.given=`Given to ${h.name} · replaced ${old.name}`;state.assigned++;state.pendingReplacement=null;document.querySelector('#modal').remove();showRewards();}
function cancelReplacement(){state.pendingReplacement=null;document.querySelector('#modal').remove();showRewards();}
function shopItemMarkup(item){
 let bought=state.shopBought.has(item.id),affordable=state.shards>=item.price,tierClass=item.id==='revive'?'major':'small';
 if(item.id==='revive'){
  let fallen=state.party.filter(h=>h.currentHp<=0),actions=bought?'<div class="shop-purchased">✓ Phoenix Thread used</div>':fallen.length?`<div class="shop-revive-actions">${fallen.map(h=>`<button ${affordable?'':'disabled'} onclick="buyShopItem('revive','${h.id}')">Revive ${h.name} · ${item.price} ✦</button>`).join('')}</div>`:'<div class="shop-safe">Your full party survived</div>';
  return `<article class="shop-card ${tierClass} ${bought?'purchased':''} ${!fallen.length?'unavailable':''}"><div class="shop-card-top"><span class="shop-icon">${item.icon}</span><span class="shop-tier">${item.tier}</span></div><div class="shop-price">${item.price} ✦</div><h3>${item.name}</h3><strong class="shop-effect">${item.effect}</strong><p>${item.desc}</p>${actions}</article>`;
 }
 let useful=item.id!=='heal'||state.party.some(h=>h.currentHp>0&&h.currentHp<h.maxHp),disabled=bought||!affordable||!useful,label=bought?'Purchased':!useful?'Already at full health':!affordable?`Need ${item.price-state.shards} more shards`:`Buy · ${item.price} ✦`;
 return `<article class="shop-card ${tierClass} ${bought?'purchased':''} ${!useful?'unavailable':''}"><div class="shop-card-top"><span class="shop-icon">${item.icon}</span><span class="shop-tier">${item.tier}</span></div><div class="shop-price">${item.price} ✦</div><h3>${item.name}</h3><strong class="shop-effect">${item.effect}</strong><p>${item.desc}</p><button ${disabled?'disabled':''} onclick="buyShopItem('${item.id}')">${label}</button></article>`;
}
function showShop(){if(!state.shopOpen){state.shopOpen=true;state.shopBought=new Set();}document.querySelector('#modal')?.remove();let w=WORLDS[state.world],budget=state.world===0?'First-shop earnings: 50 shards':'Earnings since the last shop: 75 shards';document.body.insertAdjacentHTML('beforeend',`<div class="overlay shop-overlay" id="modal"><section class="panel modal shop-modal"><div class="shop-heading"><div><div class="eyebrow">The elite path is clear</div><h2>The Wayfarer's Reliquary</h2><p>Prepare for ${w.mobs[4][0]}. Buy any relics you can afford—or save every shard for a stronger future shop.</p></div><div class="shop-wallet"><span>Echo shards</span><b>✦ ${state.shards}</b></div></div><div class="shop-income"><span>Shard rewards</span><b>Normal +10</b><i></i><b>Elite +20</b><i></i><b>Boss +25</b><small>${budget}</small></div><div class="shop-grid">${SHOP_ITEMS.map(shopItemMarkup).join('')}</div><div class="shop-footer"><small>Unused shards carry forward. Each relic can be purchased once per shop.</small><button class="primary" onclick="leaveShop()">Face the boss</button></div></section></div>`);}
function buyShopItem(id,heroId){let item=SHOP_ITEMS.find(x=>x.id===id);if(!state.shopOpen||!item||state.shopBought.has(id)||state.shards<item.price)return;if(id==='revive'){let hero=state.party.find(h=>h.id===heroId&&h.currentHp<=0);if(!hero)return;hero.currentHp=hero.maxHp;hero.burn=0;}else if(id==='heal'){if(!state.party.some(h=>h.currentHp>0&&h.currentHp<h.maxHp))return;state.party.filter(h=>h.currentHp>0).forEach(h=>h.currentHp=h.maxHp);}else if(id==='damage')state.pendingDamageBonus+=2;else if(id==='defense')state.pendingDefenseBonus+=2;state.shards-=item.price;state.shopBought.add(id);showShop();}
function advanceRun(campHeal=true){state.level++;if(state.level>4){state.world++;state.level=0;state.party.forEach(h=>h.currentHp=h.maxHp);state.log=[];}else if(campHeal)state.party.filter(h=>h.currentHp>0).forEach(h=>heal(h,8));startEncounter();}
function continueRun(){document.querySelector('#modal').remove();state.pendingReplacement=null;if(state.level===3){showShop();return;}advanceRun(true);}
function leaveShop(){document.querySelector('#modal')?.remove();state.shopOpen=false;advanceRun(false);}
function retainedAbility(h){return h.abilities.map((ability,index)=>({ability,index})).sort((a,b)=>(b.ability.rank||1)-(a.ability.rank||1)||b.index-a.index)[0]?.ability||h.start;}
function partyFell(){state.animating=false;state.fx=null;state.livesRemaining=Math.max(0,state.livesRemaining-1);state.pendingEchoOptions=state.party.map(h=>{let ability=retainedAbility(h);return {heroId:h.id,name:h.name,role:h.role,icon:h.icon,art:h.art,ability:{...ability,rank:ability.rank||1,desc:abilityText(ability)}};});render();showDeath();}
function showDeath(){let final=state.livesRemaining===0;document.body.insertAdjacentHTML('beforeend',`<div class="overlay" id="modal"><section class="panel modal defeat-modal"><div class="eyebrow">Life lost · ${state.livesRemaining}/5 remain</div><h2 class="death-title">${final?'The fifth flame is extinguished':'Your expedition has fallen'}</h2><p>${final?'The cycle closes, but one final memory can still be bound.':'Choose one hero to leave behind as an Echo. Their highest-ranked ability—and its current rank—will survive the fall.'}</p><div class="death-echo-grid">${state.pendingEchoOptions.map(e=>`<button class="death-echo-card" onclick="forgeEcho('${e.heroId}')"><span class="death-echo-art">${e.art?`<img src="${e.art}" alt="${e.name}" />`:e.icon}</span><span class="class">${e.role}</span><b>${e.name}'s Echo</b><small>${e.ability.icon} ${e.ability.name} · Rank ${e.ability.rank||1}</small><em>Bind this memory</em></button>`).join('')}</div><div class="life-loss-row">${[0,1,2,3,4].map(i=>`<i class="life ${i>=state.livesRemaining?'lost':''}"></i>`).join('')}</div></section></div>`)}
function forgeEcho(heroId){let option=state.pendingEchoOptions.find(e=>e.heroId===heroId);if(!option)return;let echo={...option,id:`echo-${++state.echoSerial}`};state.echoes.push(echo);if(state.equippedEchoIds.length<MAX_EQUIPPED_ECHOES)state.equippedEchoIds.push(echo.id);state.pendingEchoOptions=[];document.querySelector('#modal')?.remove();if(state.livesRemaining<=0){showFinalDefeat(echo);return;}reformParty();}
function reformParty(){state.level=0;state.selected=[];state.screen='select';state.party=[];state.rewards=[];state.pendingReplacement=null;state.learnedAbilities=new Set();state.cooldowns={};state.exhausted=new Set();render();}
function showFinalDefeat(echo){document.body.insertAdjacentHTML('beforeend',`<div class="overlay" id="modal"><section class="panel modal final-defeat"><div class="eyebrow">No lives remain</div><h2 class="death-title">The campaign becomes an echo</h2><p>${echo.name}'s <b>${echo.ability.name}</b> survived at Rank ${echo.ability.rank||1}, but there is no living party left to carry it.</p><div class="final-echo">${echo.icon} ${echo.name}'s Echo · ${echo.ability.icon} ${echo.ability.name} R${echo.ability.rank||1}</div><button class="primary" onclick="location.reload()">Begin a new cycle</button></section></div>`)}
function castEchoEffect(e,multiplier=1,allowKill=false){let a=e.ability,target=currentTarget(),damage=Math.max(0,Math.floor((a.value||0)*multiplier)),restored=0,dealt=0;if(a.type==='heal'){let amount=Math.max(1,damage);state.party.filter(h=>h.currentHp>0).forEach(h=>{let before=h.currentHp;heal(h,amount);restored+=h.currentHp-before;});state.log.push(`<b>${e.name}'s Echo</b> restores ${restored} party health with ${a.name}.`);return;}if(target&&damage){let index=state.enemies.indexOf(target),before=target.hp,veiled=Math.min(target.veil||0,damage);if(veiled){target.veil=0;damage-=veiled;state.log.push(`${target.name}'s Veil reduces Echo damage by <b>${veiled}</b>.`);}let blocked=Math.min(target.armor||0,damage),impact=damage-blocked;target.armor-=blocked;target.hp=allowKill?target.hp-impact:Math.max(1,target.hp-impact);dealt=before-target.hp;if(blocked)state.log.push(`${target.name}'s armor blocks <b>${blocked}</b> Echo damage.`);if(state.fx){if(dealt)state.fx.enemyDamage.push({index,amount:dealt});if(!state.fx.hitTargets.includes(index))state.fx.hitTargets.push(index);if(before>0&&target.hp<=0)state.fx.defeated.push(index);}}if(a.heal){let amount=Math.max(1,Math.floor(a.heal*multiplier)),wounded=lowest(),before=wounded?.currentHp||0;heal(wounded,amount);restored=(wounded?.currentHp||0)-before;}if(multiplier>=1&&target?.hp>0){if(a.type==='poison')target.poison+=a.dot||3;if(a.type==='weaken')target.weakened=Math.max(target.weakened,a.weaken||4);if(a.type==='expose')target.expose=Math.max(target.expose,a.bonus||6);if(a.type==='evade')state.evade=state.intent?.targetId||nextLiving()?.id||null;if(a.type==='cry'){state.boost=2;state.boostPower=a.power||3;}}state.log.push(`<b>${e.name}'s Echo</b> casts ${a.name}${dealt?` for ${dealt} damage`:''}${restored?` and restores ${restored} health`:''}.`);}
function summonEcho(echoId){let e=state.echoes.find(echo=>echo.id===echoId&&state.equippedEchoIds.includes(echo.id));if(!e||state.echoUsed||state.animating||!currentTarget())return;state.echoUsed=true;state.animating=true;state.fx={kind:'hero',heroId:`echo:${e.id}`,abilityName:e.ability.name,enemyDamage:[],hitTargets:[],defeated:[],heals:[],heroDamages:[],heroDamage:null};castEchoEffect(e,1,true);if(!state.enemies[state.intent?.attackerIndex]||state.enemies[state.intent.attackerIndex].hp<=0)planEnemyIntent();render();if(state.enemies.every(enemy=>enemy.hp<=0)){setTimeout(victory,700);return;}setTimeout(()=>{state.animating=false;state.fx=null;render();},600);}
function endGame(){document.body.insertAdjacentHTML('beforeend',`<div class="overlay"><section class="panel modal"><div class="eyebrow">The cycle is broken</div><h2>Five worlds remember your name</h2>${state.scene?.outro?`<div class="story-beat"><span>${state.scene.name}</span><p>${state.scene.outro}</p></div>`:''}<p>You defeated the End of Five with ${state.livesRemaining} lives and ${state.echoes.length} ${state.echoes.length===1?'Echo':'Echoes'} remaining in the archive.</p><button class="primary" onclick="location.reload()">Play another cycle</button></section></div>`)}
render();
